const pipeline = (x) => x();

const importers = [
  async (path) => {
    if (!/^(?:\.\.\/\.\.\/packages\/backpack-web\/src\/(?!\.)(?=.)[^/]*?\/src(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.stories\.(ts|tsx|js|jsx))$/.exec(path)) {
      return;
    }
  
    const pathRemainder = path.substring(32);
    return import(
      /* webpackChunkName: "[request]" */
      /* webpackInclude: /(?!.*node_modules)(?:\/packages\/backpack-web\/src\/(?!\.)(?=.)[^/]*?\/src(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.stories\.(ts|tsx|js|jsx))$/ */
      '../../packages/backpack-web/src/' + pathRemainder
    );
  }
  
];

export async function importFn(path) {
  for (let i = 0; i < importers.length; i++) {
    const moduleExports = await pipeline(() => importers[i](path));
    if (moduleExports) {
      return moduleExports;
    }
  }
}